<template><div class="toolbar"><el-input v-model="q" placeholder="查询应用"/><el-button @click="load">查询</el-button><el-button type="primary" @click="open()">新建</el-button></div><el-table :data="rows" border><el-table-column prop="name" label="应用名称"/><el-table-column prop="regionName" label="所属区域"/><el-table-column prop="orgName" label="所属组织"/><el-table-column prop="permission" label="权限"/><el-table-column prop="ip" label="设备 IP"/><el-table-column prop="status" label="状态"/><el-table-column prop="createdAt" label="创建时间"/><el-table-column label="操作" width="160"><template #default="s"><el-button @click="open(s.row)">修改</el-button><el-button type="danger" @click="del(s.row.id)">删除</el-button></template></el-table-column></el-table><el-dialog v-model="show" title="应用编辑"><el-form :model="form"><el-form-item label="应用名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="所属区域"><el-select v-model="form.regionId"><el-option v-for="r in regions" :label="r.name" :value="r.id"/></el-select></el-form-item><el-form-item label="所属组织"><el-select v-model="form.orgId"><el-option v-for="o in orgs" :label="o.name" :value="o.id"/></el-select></el-form-item><el-form-item label="权限"><el-input v-model="form.permission"/></el-form-item><el-form-item label="设备 IP"><el-input v-model="form.ip"/></el-form-item><el-form-item label="状态"><el-select v-model="form.status"><el-option label="运行中" value="运行中"/><el-option label="维护中" value="维护中"/><el-option label="停用" value="停用"/></el-select></el-form-item></el-form><template #footer><el-button type="primary" @click="save">保存</el-button></template></el-dialog></template>
<script setup>import{ref,onMounted}from'vue';import{api}from'../api/http';const rows=ref([]),regions=ref([]),orgs=ref([]),q=ref(''),show=ref(false),form=ref({status:'运行中'}),user=JSON.parse(localStorage.getItem('user'));async function load(){rows.value=(await api.get('/apps',{params:{q:q.value}})).data;regions.value=(await api.get('/regions')).data;orgs.value=(await api.get('/orgs')).data}function open(r={status:'运行中'}){form.value={...r};show.value=true}async function save(){const data={...form.value,username:user.username};form.value.id?await api.put('/apps/'+form.value.id,data):await api.post('/apps',data);show.value=false;load()}async function del(id){await api.delete('/apps/'+id,{params:{username:user.username}});load()}onMounted(load)</script>
